export function getCardDef(defId: string): CardDef {
  const def = CARDS[defId];
  if (!def) throw new Error(`Unknown card: ${defId}`);
  return def;
}

/** Resolves an instance to its effective definition, applying upgrade overrides. */
export function resolveCard(card: CardInstance): CardDef {
  const def = getCardDef(card.defId);
  if (!card.upgraded || !def.upgrade) return def;
  return { ...def, ...def.upgrade, name: `${def.name}+` };
}

let nextInstanceId = 1;

export function makeCard(defId: string, upgraded = false): CardInstance {
  getCardDef(defId); // validate id early
  return { instanceId: nextInstanceId++, defId, upgraded };
}

/** The starting deck: 5 Strikes, 4 Defends, 1 Bash. */
export function makeStarterDeck(): CardInstance[] {
  const deck: CardInstance[] = [];
  for (let i = 0; i < 5; i++) deck.push(makeCard('strike'));
  for (let i = 0; i < 4; i++) deck.push(makeCard('defend'));
  deck.push(makeCard('bash'));
  return deck;
}
